//! The fleet ledger — a Thoth conversation anti-queue over live leases.
//!
//! Mirrors `Gnosis.ThothConversationAntiQueue`: the ledger is an internal
//! self-accountability surface, not an external enforcement queue. Each live
//! subagent is a *held promise* Thoth makes to itself — a lease it must keep
//! renewing until it is explicitly reaped (the anti-queue "release"). The
//! ledger is `heldOpen` while any subagent is live, and `nextTaskPressure`
//! picks the most-due subagent to review next.

use crate::budget::{Caste, FleetProfile};
use serde::{Deserialize, Serialize};

fn now_secs() -> u64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_secs())
        .unwrap_or(0)
}

/// One held promise: a leased, UCAN-rooted, sandboxed subagent.
#[derive(Serialize, Deserialize, Clone, Debug)]
pub struct Subagent {
    /// Short id; the swarm `source_id` and the basis of the guard name.
    pub id: String,
    /// monster-guard plugin/command name (`agent-<id>`); the revoke handle.
    pub name: String,
    /// The subagent's own DID — its first-class identity (its secret lives in a
    /// 0600 keyfile, not here), used for audit + future invocation signatures.
    pub did: String,
    /// DID of the capability holder who spawned this subagent (audit trail).
    pub spawned_by: String,
    pub caste: Caste,
    pub caps: Vec<String>,
    /// The real distributed-inference node launched under the lease.
    pub node_bin: String,
    pub node_args: Vec<String>,
    pub lease_secs: u64,
    /// Unix seconds at spawn.
    pub started_at: u64,
    /// Bule diversity cost charged against the manifold ceiling (default 1).
    pub bule_cost: u32,
    /// Best-effort pid of the supervising `monster-guard run` child.
    pub pid: Option<i32>,
    /// The conduct oath this subagent swore at admission. After the Ulysses
    /// pact this is the *path to the signed oath-token* the agent minted with its
    /// own keypair (`$MONSTER_GUARD_HOME/oath-tokens/<id>.oath.ucan`) — handed to
    /// monster-guard, which verifies the signature. `None` when no oath was
    /// sworn. Recorded here so the Thoth fleet frame can keep each agent's oath
    /// "front of mind".
    #[serde(default)]
    pub oath: Option<String>,
    /// True when the oath was cryptographically sworn: the agent signed its oath
    /// into a UCAN oath-token with its own keypair (the Ulysses pact). The crypto
    /// proof, surfaced in the fleet frame so it stays front of mind.
    #[serde(default)]
    pub oath_signed: bool,
    /// The DID that signed the oath-token — the agent's own DID (Ulysses: the
    /// swearer is the bound). `None` when no oath was sworn.
    #[serde(default)]
    pub oath_sworn_by: Option<String>,
    /// Delegation depth: the length of the authorizing UCAN chain at spawn
    /// (`verify_chain(...).chain.len()`). A root-issued spawn (root holder spawns
    /// directly) is depth 1; each attenuated delegation hop adds 1. Recorded so
    /// the recursive-accountability tree structure is visible — how far down the
    /// delegation a spawn was authorized. Defaults to 0 for rows written before
    /// lineage existed (an unknown/legacy depth).
    #[serde(default)]
    pub depth: usize,
}

impl Subagent {
    /// Age in seconds — the anti-queue pressure: an older held promise is more
    /// "due" for review (renewal / reap). Mirrors `nextTaskPressure` ordering.
    pub fn pressure(&self, now: u64) -> u64 {
        now.saturating_sub(self.started_at)
    }
}

/// The whole fleet: the set of held promises plus cumulative vent burden.
#[derive(Serialize, Deserialize, Clone, Debug, Default)]
pub struct Fleet {
    pub subagents: Vec<Subagent>,
    /// Cumulative reaps (the colony's `ventBurden`).
    pub vent_burden: u32,
    /// Monotonic frame sequence for emitted Thoth fleet frames.
    pub seq: u64,
}

impl Fleet {
    pub fn breeders(&self) -> u32 {
        self.subagents
            .iter()
            .filter(|s| s.caste == Caste::Breeder)
            .count() as u32
    }
    pub fn scouts(&self) -> u32 {
        self.subagents
            .iter()
            .filter(|s| s.caste == Caste::Scout)
            .count() as u32
    }
    pub fn live(&self) -> u32 {
        self.subagents.len() as u32
    }

    /// The colony FRF profile this fleet presents to the admission budget.
    /// Reproductive void = spare ceiling headroom (the spawn capacity that
    /// feeds both fork and race).
    pub fn profile(&self, population_ceiling: u32) -> FleetProfile {
        let live = self.live();
        FleetProfile {
            breeders: self.breeders(),
            reproductive_void: population_ceiling.saturating_sub(live),
            scouts: self.scouts(),
            vent_burden: self.vent_burden,
        }
    }

    pub fn find(&self, id: &str) -> Option<&Subagent> {
        self.subagents.iter().find(|s| s.id == id)
    }

    pub fn add(&mut self, agent: Subagent) {
        self.subagents.push(agent);
    }

    /// Remove a subagent and vent (the anti-queue release on reap).
    pub fn reap(&mut self, id: &str) -> Option<Subagent> {
        if let Some(idx) = self.subagents.iter().position(|s| s.id == id) {
            self.vent_burden += 1;
            Some(self.subagents.remove(idx))
        } else {
            None
        }
    }

    /// `heldOpen`: the ledger holds at least one outstanding promise.
    pub fn held_open(&self) -> bool {
        !self.subagents.is_empty()
    }

    /// The most-due held promise — `nextTaskPressure`. None when empty.
    pub fn most_pressured(&self, now: u64) -> Option<&Subagent> {
        self.subagents.iter().max_by_key(|s| s.pressure(now))
    }

    /// The oldest scout — the autonomic reap target (never a breeder, so the
    /// two-queen floor is respected by construction).
    pub fn oldest_scout(&self) -> Option<&Subagent> {
        self.subagents
            .iter()
            .filter(|s| s.caste == Caste::Scout)
            .min_by_key(|s| s.started_at)
    }

    pub fn next_seq(&mut self) -> u64 {
        let s = self.seq;
        self.seq += 1;
        s
    }

    /// Per-live-subagent oath records for the Thoth fleet frame's `oaths` array —
    /// what each agent swore, whether it was cryptographically signed (the
    /// Ulysses pact), the DID that signed it, AND the STABLE spawner identity
    /// (`spawned_by`) with the spawner's reputation `trust` — kept front of mind
    /// so admission-by-trust is visible alongside the conduct each agent is bound
    /// to. The spawner's trust is computed from the breach audit log.
    pub fn oaths(&self) -> Vec<OathEntry> {
        self.subagents
            .iter()
            .map(|s| OathEntry {
                id: s.id.clone(),
                oath: s.oath.clone(),
                signed: s.oath_signed,
                sworn_by: s.oath_sworn_by.clone(),
                spawned_by: s.spawned_by.clone(),
                spawner_trust: crate::trust::trust_of(&s.spawned_by),
                depth: s.depth,
            })
            .collect()
    }
}

/// One subagent's oath, as surfaced in the Thoth fleet frame. Carries the crypto
/// proof (`signed`, `sworn_by`) so the Ulysses pact stays front of mind, plus the
/// STABLE spawner identity (`spawned_by`) and that spawner's reputation
/// (`spawner_trust`, 0.0..=1.0) so admission-by-trust is front of mind too.
#[derive(Debug, Clone, PartialEq)]
pub struct OathEntry {
    pub id: String,
    pub oath: Option<String>,
    pub signed: bool,
    pub sworn_by: Option<String>,
    /// The UCAN holder DID that spawned this agent — the identity trust attaches
    /// to. Empty for ledger rows written before `spawned_by` existed.
    pub spawned_by: String,
    /// The spawner's reputation in `0.0..=1.0` (1.0 = no breaches). Computed from
    /// the breach audit log.
    pub spawner_trust: f64,
    /// Delegation depth: the authorizing UCAN chain length at spawn (1 = a
    /// root holder spawned directly; >1 = spawned through that many attenuated
    /// delegation hops). Surfaced so the recursive-accountability tree is visible
    /// in the fleet frame. 0 for legacy rows with no recorded depth.
    pub depth: usize,
}

/// Convenience: a fresh subagent record stamped at the current time.
#[allow(clippy::too_many_arguments)]
pub fn new_subagent(
    id: String,
    name: String,
    did: String,
    spawned_by: String,
    caste: Caste,
    caps: Vec<String>,
    node_bin: String,
    node_args: Vec<String>,
    lease_secs: u64,
    pid: Option<i32>,
    oath: Option<String>,
    oath_signed: bool,
    oath_sworn_by: Option<String>,
    depth: usize,
) -> Subagent {
    Subagent {
        id,
        name,
        did,
        spawned_by,
        caste,
        caps,
        node_bin,
        node_args,
        lease_secs,
        started_at: now_secs(),
        bule_cost: 1,
        pid,
        oath,
        oath_signed,
        oath_sworn_by,
        depth,
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn agent(id: &str, caste: Caste, started_at: u64) -> Subagent {
        Subagent {
            id: id.into(),
            name: format!("agent-{id}"),
            did: "did:key:zAgent".into(),
            spawned_by: "did:key:zTest".into(),
            caste,
            caps: vec!["net".into()],
            node_bin: "aeon-monitor".into(),
            node_args: vec![],
            lease_secs: 60,
            started_at,
            bule_cost: 1,
            pid: None,
            oath: None,
            oath_signed: false,
            oath_sworn_by: None,
            depth: 1,
        }
    }

    #[test]
    fn empty_fleet_not_held_open() {
        // Mirrors `empty_self_antiqueue_not_held`.
        assert!(!Fleet::default().held_open());
    }

    #[test]
    fn populated_fleet_is_held_open() {
        let mut f = Fleet::default();
        f.add(agent("a", Caste::Breeder, 100));
        assert!(f.held_open());
    }

    #[test]
    fn profile_counts_castes_and_void() {
        let mut f = Fleet::default();
        f.add(agent("a", Caste::Breeder, 0));
        f.add(agent("b", Caste::Scout, 0));
        f.add(agent("c", Caste::Scout, 0));
        let p = f.profile(10);
        assert_eq!(p.breeders, 1);
        assert_eq!(p.scouts, 2);
        assert_eq!(p.reproductive_void, 7); // 10 ceiling − 3 live
    }

    #[test]
    fn most_pressured_is_oldest() {
        let mut f = Fleet::default();
        f.add(agent("young", Caste::Scout, 500));
        f.add(agent("old", Caste::Scout, 100));
        assert_eq!(f.most_pressured(1000).unwrap().id, "old");
    }

    #[test]
    fn new_subagent_records_the_oath() {
        // The sworn oath (now a signed oath-token path) is threaded through
        // new_subagent and lands on the record, along with the crypto proof.
        let s = new_subagent(
            "o".into(),
            "agent-o".into(),
            "did:key:zAgent".into(),
            "did:key:zSpawner".into(),
            Caste::Scout,
            vec!["net".into()],
            "fat-station".into(),
            vec![],
            60,
            Some(1),
            Some("oath-tokens/o.oath.ucan".into()),
            true,
            Some("did:key:zAgent".into()),
            2,
        );
        assert_eq!(s.oath.as_deref(), Some("oath-tokens/o.oath.ucan"));
        assert!(s.oath_signed, "the Ulysses pact records the crypto proof");
        assert_eq!(s.oath_sworn_by.as_deref(), Some("did:key:zAgent"));
        assert_eq!(s.depth, 2, "the delegation depth lands on the record");

        // No oath sworn → None / unsigned (today's behavior preserved).
        let none = new_subagent(
            "n".into(),
            "agent-n".into(),
            "did:key:zAgent".into(),
            "did:key:zSpawner".into(),
            Caste::Scout,
            vec![],
            "fat-station".into(),
            vec![],
            60,
            None,
            None,
            false,
            None,
            1,
        );
        assert!(none.oath.is_none());
        assert!(!none.oath_signed);
        assert!(none.oath_sworn_by.is_none());
        assert_eq!(none.depth, 1, "a root-issued spawn is depth 1");
    }

    #[test]
    fn fleet_oaths_pairs_id_with_oath() {
        let mut f = Fleet::default();
        let mut a = agent("a", Caste::Breeder, 0);
        a.oath = Some("oath-tokens/a.oath.ucan".into());
        a.oath_signed = true;
        a.oath_sworn_by = Some("did:key:zA".into());
        f.add(a);
        f.add(agent("b", Caste::Scout, 0)); // no oath
        let oaths = f.oaths();
        assert_eq!(oaths.len(), 2);
        assert_eq!(oaths[0].id, "a");
        assert_eq!(oaths[0].oath.as_deref(), Some("oath-tokens/a.oath.ucan"));
        assert!(oaths[0].signed, "the crypto proof is surfaced");
        assert_eq!(oaths[0].sworn_by.as_deref(), Some("did:key:zA"));
        // The spawner identity is surfaced; with no breach log on disk a spawner
        // scores full trust (1.0).
        assert_eq!(oaths[0].spawned_by, "did:key:zTest");
        assert_eq!(oaths[0].spawner_trust, 1.0, "no breaches -> full trust");
        assert_eq!(oaths[0].depth, 1, "the delegation depth is surfaced");
        assert_eq!(oaths[1].id, "b");
        assert!(oaths[1].oath.is_none());
        assert!(!oaths[1].signed);
        assert!(oaths[1].sworn_by.is_none());
        assert_eq!(oaths[1].spawner_trust, 1.0);
    }

    #[test]
    fn reap_vents_and_removes() {
        let mut f = Fleet::default();
        f.add(agent("a", Caste::Scout, 0));
        assert!(f.reap("a").is_some());
        assert_eq!(f.vent_burden, 1);
        assert!(!f.held_open());
        assert!(f.reap("a").is_none());
    }
}
